mapper.update:
UPDATE auth_state
SET status = #{state.status}, credential_json = #{state.credentialJson},
    metadata_json = #{state.metadataJson}, updated_at = #{state.updatedAt}
WHERE tenant_id = #{state.tenantId} AND user_id = #{state.userId} AND provider = #{state.provider}

mapper.select:
SELECT qr_session_id AS "qrSessionId", tenant_id AS "tenantId", user_id AS "userId",
       chat_session_id AS "chatSessionId", expires_at AS "expiresAt",
       created_at AS "createdAt", updated_at AS "updatedAt"
FROM boss_qr_login_session
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND expires_at > #{now}
ORDER BY created_at DESC
LIMIT 1

SELECT qr_session_id AS "qrSessionId", tenant_id AS "tenantId", user_id AS "userId",
       chat_session_id AS "chatSessionId", expires_at AS "expiresAt",
       created_at AS "createdAt", updated_at AS "updatedAt"
FROM boss_qr_login_session
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND chat_session_id = #{chatSessionId}
  AND expires_at > #{now}
ORDER BY created_at DESC
LIMIT 1
